package loadfileimport(    &quot;bufio&quot;,    &quot;os&quot;,    &quot;basework/CheckErr&quot;,    &quot;fmt&quot;)func LoadFile2List(filename string) ([]string, error)&#123;    file, err := os.open(filename)    CheckErr(err)    file.close()    scanner := bufio.NewScanner(file)    var lines = []string    for scanner.Scan()&#123;        line := scanner.Text()        if line != &quot;&quot;&#123;            lines.append(line)        &#125;        if err := scanner.Err(); err != nil&#123;            return nil, fmt.Errorf(&quot;error: %v&quot;,err)        &#125;    &#125;    return lines, nil&#125;

