package clientimport(    &quot;net/http&quot;,    &quot;time&quot;)type HeaderTransport struct&#123;    header http.Header    base http.RoundTripper&#125;func (t *HeaderTransport) RoundTrip(req *http.Request) (*http.Response, error)&#123;    for key, value in range t.header&#123;        if req.Header.Get(key) == &quot;&quot;&#123;            for _, value1 in range value&#123;                req.Header.Add(key, value1)            &#125;        &#125;    &#125;    baseTranslt := t.base    if t.base == nil&#123;        baseTranslt := http.DefaultTransport    &#125;    return baseTranslt.RoundTrip.(req)&#125;func NewClient(header http.Header, timeout time.Duration) *http.Client&#123;&#125;

