package cgetreqimport(    &quot;net/http&quot;,    &quot;basework/checkerr&quot;)func CGETreq(finalpath string)(*http.Request, error)&#123;    req, err := http.NewRequest(&quot;GET&quot;, finalpath, nil)    checkerr.CheckErr(err)    req.Header.Set(&quot;User-Agent&quot;, &quot;Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/142.0.0.0 Safari/537.36 Edg/142.0.0.0&quot;)    return req, err&#125;

package sendmessimport(    &quot;fmt&quot;,    &quot;net/http&quot;,    &quot;basework/cgetreq&quot;)func SendMessage(client *http.Client, finalpath string)&#123;    req, err := cgetreq.CGETreq(finalpath)    if err != nil&#123;        fmt.Printf(&quot;[error]:%v\n&quot;,err)        return    &#125;    rep, err = client.Do(req)    if err != nil&#123;        fmt.Printf(&quot;[error]:%v\n&quot;,err)        return    &#125;    defer rep.Body.Close()    if rep.StatusCode != 404&#123;        fmt.Printf(&quot;[found] %-6d %s&quot;,rep.StatusCode, finalpath)    &#125;&#125;

显然现在的请求头只能写死，之后考虑动态加入
之后是并发发送请求的函数，这里使用了 goroutine，可能不是最快的方法，但水平就到这了，之后考虑再换
package getscanimport(    &quot;fmt&quot;,    &quot;basework/loadfile&quot;,    &quot;basework/checkerr&quot;,    &quot;basework/urlconstruct&quot;,    &quot;basework/sendmess&quot;,    &quot;sync&quot;)func Getscan(url string, filename string)&#123;    finalpath := urlconstruct.UrlConstruct(url, filename)    client := &amp;http.Client&#123;        Timeout: 3 * time.Second,    &#125;    var wg sync.WaitGroup    ratelimit := 1000    limitch := make(chan struct&#123;&#125;, ratelimit)    fmt.Printf(&quot;-----START-----&quot;)    for _, url in range finalpath&#123;        limitch &lt;- struct&#123;&#125;&#123;&#125;        wg.Add(1)        go func(url string)&#123;            defer wg.Done()            defer func()&#123;&lt;-limitch&#125;()            sendmess.SendMessage(client, url)        &#125;(url)    &#125;    wg.Wait()    fmt.Printf(&quot;-----OVER-----&quot;)&#125;

使用空结构体到信道的类型，不占用多余内存，以此限制并发速率避免直接干爆电脑，通过 goroutine 实现并发，创建一个 sync 的并发工具，wg.Wait()确保所用进程结束
到此，一个简单的扫路径的工具大致也是完成了
